;        OntologyType ontologyType = OntologyType.parse(metaStep.type);        List<ValueConstraint.BaseDesc> subDescs = Lists.newArrayList();        Set<IEndTypeGetter.EndType> endTypes = null;        for (ValueConstraint.BaseDesc desc : descs) {            endTypes = desc.specializedTypeEnds();            if (endTypes.contains(ontologyType.getEndType())) {                subDescs.add(desc);            }        }        //  return descFilter(descs, endType, null);        return subDescs;    }    private static MetadataOfValueType getMetaStep() {        IPluginContext threadLocalCtx = IPluginContext.getThreadLocalInstance();        Context context = threadLocalCtx.getContext();        return                Objects.requireNonNull((MetadataOfValueType) context.get(MetadataOfValueType.class.getName()),                        "metaStep can not be null");    }    public static String generateConstraintHelp() {        MetadataOfValueType metaStep = getMetaStep();        OntologyType ontologyType = OntologyType.parse(metaStep.type);        return "为‘" + ontologyType.getLiteria() + "’类型设置值约束";    }    @Override    protected void processPreSaved(IPluginContext pluginContext, Context currentCtx,                                   OneStepOfMultiSteps[] preSavedStepPlugins) {    }    @TISExtension    public static class Desc extends BasicDesc {        @Override        public String getDisplayName() {            return "第二步";        }        @Override        public String getStepDescription() {            return "Constraints";        }        @Override        public Step getStep() {            return Step.Step2;        }        @Override        public Optional<BasicDesc> nextPluginDesc() {            return Optional.empty();        }    }}